# verify.jl -- triangulate Phase 6 Problems oracle, then emit
# test/_oracle_problems.jl.
#
# Sources:
#   oracles_wolfram.txt — Mathematica closed-form WeierstrassP at all
#                         five test points (Float64) plus 78-digit
#                         BigFloat-256 string for z=30.
#   FW 2011 paper       — reference values pinned at lines 301, 372 of
#                         the markdown; cross-checked inline below.
#
# We do NOT cross-check via mpmath.odefun for Phase 6.  That worked
# for Phase 5's short-range tests (z = 0.5) but mpmath.odefun
# integrating u'' = 6u^2 over z ∈ [0, 30] crosses ~12 lattice poles
# of ℘ and takes more than 10 minutes / fails to converge near each
# pole — it has no Padé extension to handle pole-crossings.  The
# 3-source consensus on the *underlying ODE* was established in
# Phase 5 (worklog 003); the 2-source consensus here (paper FW
# reference ≡ Mathematica WeierstrassP) is the appropriate Phase-6
# discipline.
#
# Usage (from project root):
#   julia --project=. external/probes/problems-oracle/verify.jl

using Printf

const HERE = @__DIR__
const PROJECT_ROOT = abspath(joinpath(HERE, "..", "..", ".."))
const O_WL = joinpath(HERE, "oracles_wolfram.txt")
const PINNED = joinpath(PROJECT_ROOT, "test", "_oracle_problems.jl")

module _OWL end
Base.include_string(_OWL, read(O_WL, String), O_WL)

function check(label, a, b; rtol)
    rel = abs(a - b) / max(abs(a), abs(b), 1e-300)
    rel < rtol || error("$label  $a  vs  $b  rel=$rel > rtol=$rtol")
    @printf("%-60s %.16g  (rel %.2e)\n", label, a, rel)
end

# ---- FW Table 5.1 paper-pinned reference values (lines 301, 372) ----
let
    check("u(30)     vs FW ref (FW2011_*.md:301)",
          _OWL.u_at_30, _OWL.u_at_30_FW_ref; rtol = 1e-14)
    check("u(10^4)   vs FW ref (FW2011_*.md:301)",
          _OWL.u_at_10000, _OWL.u_at_10000_FW_ref; rtol = 1e-14)
    check("u(28.261) vs FW ref (FW2011_*.md:372)",
          _OWL.u_at_28261, _OWL.u_at_28261_FW_ref; rtol = 1e-14)
end

# ---- BigFloat-256 string round-trip (test 6.1.4) ----
let
    setprecision(BigFloat, 256) do
        u_bf  = parse(BigFloat, _OWL.u_at_30_80dps_str)
        up_bf = parse(BigFloat, _OWL.up_at_30_80dps_str)
        @assert isapprox(Float64(u_bf),  _OWL.u_at_30;  rtol = 1e-14) "BF round-trip on u_at_30"
        @assert isapprox(Float64(up_bf), _OWL.up_at_30; rtol = 1e-14) "BF round-trip on up_at_30"
        @printf("u(30) at 78-dps (BF-256 round-trip) ≡ closed-form Float64\n")
    end
end

println()

# ---- Emit canonical pinned file ----
open(PINNED, "w") do io
    print(io, """
# test/_oracle_problems.jl -- Phase 6 oracle, pinned values.
#
# Auto-generated by external/probes/problems-oracle/verify.jl.
# Do NOT hand-edit.
#
# Sources (cross-checked above to <1e-14 rel where comparable):
#   - Mathematica WeierstrassP[z + c1, {0, c2}], c1 = -1, c2 = 2.
#   - FW 2011 Table 5.1 reference values from FW2011_*.md lines
#     301 (u(30), u(10^4)) and 372 (u(28.261)).
#
# Phase-5 worklog 003 established the 3-source consensus
# (closed-form ≡ NDSolve ≡ mpmath.odefun) on the underlying ODE
# u'' = 6u^2 over short ranges.  Long-range mpmath.odefun integration
# is infeasible (~12 lattice poles between 0 and 30), so Phase 6
# relies on the 2-source closed-form ≡ paper consensus.

""")
    print(io, read(O_WL, String))
end

println("Wrote ", PINNED)
